// API Key authentication check - timing-safe comparison
const headers = $input.first().json.headers || {};

// Case-insensitive header lookup (defense against platform normalization changes)
const headerKeys = Object.keys(headers);
const apiKeyHeader = headerKeys.find(k => k.toLowerCase() === 'x-api-key');
const providedKey = apiKeyHeader ? headers[apiKeyHeader] : '';
const expectedKey = $env.RVC_API_KEY;

// Timing-safe comparison - prevents timing attacks on API key
function timingSafeEqual(a, b) {
  if (typeof a !== 'string' || typeof b !== 'string') return false;
  const MAX_LEN = 256;
  if (a.length > MAX_LEN || b.length > MAX_LEN) return false;

  let result = 0;
  // Constant-time comparison: always iterate MAX_LEN, use 0 for out-of-bounds
  for (let i = 0; i < MAX_LEN; i++) {
    const charA = i < a.length ? a.charCodeAt(i) : 0;
    const charB = i < b.length ? b.charCodeAt(i) : 0;
    result |= charA ^ charB;
  }
  // Include length check in constant-time result
  result |= (a.length === b.length) ? 0 : 1;
  return result === 0;
}

// Always validate if server has key configured; reject if client provides key when server has none
if (expectedKey ? !timingSafeEqual(providedKey || '', expectedKey) : providedKey) {
  throw new Error('Authentication failed');
}

const input = $input.first().json || {};
const model = input.model || '';
const audioPath = input.audio_path || '';
const audio = input.audio || '';

// === ENHANCED PATH TRAVERSAL PROTECTION ===
// Blocks: ../, ..\, %2e%2e%2f, %252e%252e%252f, %2f, %252f, null bytes, absolute paths, Windows drive letters
const pathTraversalPattern = /(\.\.[/\\]|%2e%2e[/\\]|%252e%252e[/\\]|%2[fF]|%252[fF]|%00|\x00|^\/|^[a-zA-Z]:\\)/i;

// Decode and normalize for Unicode NFC attack detection
let normalizedPath;
try {
  normalizedPath = decodeURIComponent(audioPath).normalize('NFC');
} catch (e) {
  throw new Error('Invalid audio_path: malformed URL encoding');
}

// === MODEL VALIDATION ===
const validModelPattern = /^[a-zA-Z0-9._-]+$/;

// === CHANNEL VALIDATION ===
// Strip # prefix and Discord special chars, then validate clean name
const channelRaw = (input.channel || 'general').replace(/^#+/, '').replace(/[<>@&]/g, '').slice(0, 100);
if (!channelRaw.match(/^[a-zA-Z0-9_-]+$/)) {
  throw new Error('Invalid channel: must be alphanumeric, dash, or underscore only');
}
const channel = channelRaw;

// === F0_METHOD ALLOWLIST ===
const validF0Methods = ['harvest', 'pm', 'dio', 'rmvpe', 'crepe', 'crepe-tiny', 'mangio-crepe', 'mangio-crepe-tiny'];
const f0Method = (input.f0_method || 'rmvpe').toLowerCase();

// === PITCH VALIDATION ===
const pitchRaw = parseInt(input.pitch ?? 0, 10);
if (isNaN(pitchRaw) || pitchRaw < -12 || pitchRaw > 12) {
  throw new Error('Invalid pitch: must be a number between -12 and +12 semitones');
}
const pitch = pitchRaw;

// === REQUIRED FIELD CHECKS ===
if (!model) {
  throw new Error('Missing required field: model');
}
if (!audio && !audioPath) {
  throw new Error('Missing required field: audio or audio_path');
}

// === PATH VALIDATION ===
if (audioPath) {
  if (pathTraversalPattern.test(audioPath) || pathTraversalPattern.test(normalizedPath)) {
    throw new Error('Path traversal detected: audio_path contains invalid sequences');
  }
}

// === MODEL VALIDATION ===
if (!validModelPattern.test(model)) {
  throw new Error('Invalid model name: must be alphanumeric, dot, dash, or underscore only');
}
if (model.length > 100) {
  throw new Error('Model name too long: max 100 characters');
}

// === F0_METHOD VALIDATION ===
if (!validF0Methods.includes(f0Method)) {
  throw new Error('Invalid f0_method: must be one of ' + validF0Methods.join(', '));
}

return [{
  json: {
    model: model,
    audio: audio,
    audio_path: audioPath,
    channel: channel,
    pitch: pitch,
    f0_method: f0Method
  }
}];

// Validate upload response path
const uploadResponse = $input.first().json || {};
const path = uploadResponse.path || '';

// Must have a path from upload - no fallback to user input
if (!path) {
  throw new Error('No audio path returned from upload service');
}

// Decode and validate the path
let decodedPath;
try {
  decodedPath = decodeURIComponent(path).normalize('NFC');
} catch (e) {
  throw new Error('Invalid upload path: malformed URL encoding');
}

// Strict validation: must be /tmp/<alphanumeric>.<audio_ext>
const validPathPattern = /^\/tmp\/[a-zA-Z0-9_-]+\.(wav|mp3|ogg|flac|webm)$/i;

// Path traversal check with URL-encoded variants
const traversalPattern = /(\.\.[/\\]|%2e%2e%2[fF]|%252e%252e%252[fF]|%2[fF]|%252[fF]|%00)/i;

// Check for traversal in both raw and decoded path
if (traversalPattern.test(path) || traversalPattern.test(decodedPath) || !validPathPattern.test(decodedPath)) {
  throw new Error('Invalid upload response path: failed validation');
}

return [{ json: { path: path, from_upload: true } }];

