try {
  // Process RVC conversion response
  const body = $input.first().json || {};
  const validatedInput = $('Validate Input').first().json || {};

  const downloadUrl = body.download_url || body.url || '';
  const success = !!downloadUrl;

  // Validate download URL doesn't contain traversal
  if (downloadUrl && /(\.\.|\\x00|%00)/.test(downloadUrl)) {
    throw new Error('Invalid download URL: contains suspicious sequences');
  }

  return [{
    json: {
      success: success,
      model: validatedInput.model || 'unknown',
      pitch: validatedInput.pitch || 0,
      f0_method: validatedInput.f0_method || 'rmvpe',
      download_url: downloadUrl,
      channel: validatedInput.channel || 'general',
      timestamp: new Date().toISOString()
    }
  }];
} catch (err) {
  throw new Error('Process Response failed: ' + err.message);
}
